sys_security_acl.script:
(function evaluateRule(current, table) {
  // Allow if admin
  if (gs.hasRole('admin')) return true;

  // Allow if user has tech roles
  if (gs.hasRole('itsm_l1_agent') || gs.hasRole('itsm_l2_agent') || 
      gs.hasRole('itsm_l3_agent') || gs.hasRole('knowledge_admin') || 
      gs.hasRole('knowledge_manager')) {
    return true;
  }

  return false;
})(current, table);
